 3→class DefaultSettingsChangeBroker(
 4→    private val subscribers: MutableSet<SettingsChangeSubscriber> = mutableSetOf(),
 5→) : SettingsChangeBroker, SettingsChangePublisher {
 6→
 7→    private val lock = Any()
 8→
 9→    override fun subscribe(subscriber: SettingsChangeSubscriber) {
10→        synchronized(lock) {
11→            subscribers.add(subscriber)
12→        }
13→    }
14→
15→    override fun unsubscribe(subscriber: SettingsChangeSubscriber) {
16→        synchronized(lock) {
17→            subscribers.remove(subscriber)
18→        }
19→    }
20→
21→    override fun publish() {
22→        val currentSubscribers = synchronized(lock) { HashSet(subscribers) }
23→
24→        for (subscriber in currentSubscribers) {
25→            subscriber.receive()
26→        }
27→    }
28→}
